// MARK: 点击空白隐藏键盘 let tap = UITapGestureRecognizer(target: self, action: #selector(InitialLaunch.hideKeyboard(tapG:))) tap.cancelsTouchesInView = false self.view.addGestureRecognizer(tap)&mdash; title: &ldquo;【iOS小白】创建APP初始设置界面&rdquo; date: 2019-08-07T18:02:28+08:00 tags: [&ldquo;iOS&rdquo;] categories: [&ldquo;&rdquo;]
draft: true 怎么切换不同的UIPickerView？ 为每一个UIPickerView设立tag let periodDaysPicker = UIPickerView() periodDaysPicker.delegate = self periodDaysPicker.dataSource = self periodDaysPicker.tag = 3
// 每个选项显示什么 func pickerView(_ pickerView: UIPickerView, titleForRow row: Int, forComponent component: Int) -&gt; String? { switch pickerView.tag { case 2: return lastDaysTextOptions[row] case 3: return periodDaysTextOptions[row] default: return &ldquo;没有选择器&rdquo; } }
